\copy (SELECT DISTINCT vocabulary_pack.CutConceptSynonymName(d.term) AS synonym_name, d.conceptid AS synonym_concept_code, 'SNOMED' AS synonym_vocabulary_id, 4180186 AS language_concept_id FROM sources_vet_sct2_desc_full d JOIN (SELECT DISTINCT ON (id) id, moduleid, active FROM sources_vet_sct2_concept_full ORDER BY id, effectivetime DESC) c_latest ON c_latest.id = d.conceptid WHERE d.moduleid = '332351000009108' AND c_latest.moduleid = '900000000000207008' AND c_latest.active = 1 ORDER BY synonym_concept_code, synonym_name) TO 'vet_synonyms_for_existing_snomed_concepts.csv' WITH CSV HEADER